这是一个标准的 JavaScript **debounce** 函数实现，附带几种常见变体：

## 基础实现

```javascript
/**
 * 创建一个防抖函数
 * @param {Function} fn      要执行的函数
 * @param {number}   delay   延迟时间（毫秒）
 * @param {Object}   options 配置选项
 * @param {boolean}  options.leading  是否在延迟开始前执行（默认 false）
 * @param {boolean}  options.trailing 是否在延迟结束后执行（默认 true）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let leadingCalled = false;

  const debounced = function (...args) {
    // 保存本次调用参数
    lastArgs = args;

    // 清除之前的定时器
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }

    // leading 模式：第一次调用立即执行
    if (leading && !leadingCalled) {
      leadingCalled = true;
      fn.apply(this, args);
      // 设置定时器，在 delay 后重置 leadingCalled
      timer = setTimeout(() => {
        timer = null;
        leadingCalled = false;
        // trailing 模式：如果 delay 期间有再次调用，延迟结束后执行最后一次
        if (trailing && lastArgs) {
          fn.apply(this, lastArgs);
          lastArgs = null;
        }
      }, delay);
      return;
    }

    // trailing 模式（默认）：延迟结束后执行最后一次调用
    if (trailing) {
      timer = setTimeout(() => {
        timer = null;
        leadingCalled = false;
        fn.apply(this, lastArgs);
        lastArgs = null;
      }, delay);
    }
  };

  /**
   * 取消防抖，取消等待中的执行
   */
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    leadingCalled = false;
  };

  /**
   * 立即执行并清空等待队列
   */
  debounced.flush = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
      if (lastArgs) {
        fn.apply(this, lastArgs);
        lastArgs = null;
      }
      leadingCalled = false;
    }
  };

  return debounced;
}
```

---

## 简洁版（日常够用）

```javascript
function debounce(fn, delay) {
  let timer = null;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}
```

---

## 使用示例

```javascript
// 1. 输入框搜索（默认 trailing）
const searchInput = document.getElementById('search');
const handleSearch = debounce((e) => {
  console.log('发送搜索请求:', e.target.value);
}, 300);
searchInput.addEventListener('input', handleSearch);

// 2. 提交按钮防抖（leading 模式：立即执行，防止重复提交）
const submitBtn = document.getElementById('submit');
const handleSubmit = debounce(
  () => console.log('表单提交中...'),
  1000,
  { leading: true, trailing: false }
);
submitBtn.addEventListener('click', handleSubmit);

// 3. 取消与立即执行
handleSearch.cancel();   // 取消等待中的调用
handleSearch.flush();    // 立即执行最后一次调用
```

---

## 原理说明

| 模式 | 表现 |
|------|------|
| **trailing** (默认) | 连续触发时只在**最后一次触发后 delay 毫秒**执行一次 |
| **leading** | 连续触发时**立即执行第一次**，之后 delay 毫秒内不再触发 |
| **leading + trailing** | 第一次立即执行 + 停止触发后 delay 毫秒再执行最后一次 |

> **核心场景**：搜索框实时查询（300ms）、窗口 resize 重绘（200ms）、按钮防重复提交（leading模式）、滚动加载更多（200ms）。

