## TypeScript Discriminated Union（可辨识联合）

Discriminated Union 是 TypeScript 中一种强大的模式，通过一个共同的**字面量属性**（discriminant/tag）来区分联合类型中的不同成员，让类型收窄变得精确可控。

### 基础例子：表单状态

```typescript
// 1. 定义共同的 discriminator 属性 'status'
type IdleState = {
  status: 'idle';
  message: string;
};

type LoadingState = {
  status: 'loading';
  progress: number;   // 0-100
};

type SuccessState = {
  status: 'success';
  data: string[];
  timestamp: number;
};

type ErrorState = {
  status: 'error';
  errorCode: number;
  errorMessage: string;
};

// 2. 联合类型
type RequestState =
  | IdleState
  | LoadingState
  | SuccessState
  | ErrorState;

// 3. 使用时通过 status 自动收窄类型
function handleState(state: RequestState) {
  switch (state.status) {
    case 'idle':
      // ✅ state 被收窄为 IdleState，可安全访问 message
      console.log(`Idle: ${state.message}`);
      break;

    case 'loading':
      // ✅ 可访问 progress
      console.log(`Loading at ${state.progress}%`);
      break;

    case 'success':
      // ✅ 可访问 data 和 timestamp
      console.log(`Got ${state.data.length} items`);
      break;

    case 'error':
      // ✅ 可访问 errorCode 和 errorMessage
      console.error(`Error ${state.errorCode}: ${state.errorMessage}`);
      break;

    default:
      // ✅ exhaustive check：如果上面有未覆盖的类型，这行会编译报错
      const _exhaustive: never = state;
  }
}
```

### 实际用途举例：API 响应

```typescript
type ApiResponse<T> =
  | { kind: 'pending' }
  | { kind: 'success'; data: T }
  | { kind: 'error'; message: string };

function renderUser(response: ApiResponse<{ name: string; age: number }>) {
  if (response.kind === 'pending') {
    return '<Spinner />';
  }
  if (response.kind === 'error') {
    return `<Error>${response.message}</Error>`;
  }
  // 此时 TypeScript 知道只剩下 success 类型
